// n8n Code node script — Slack HMAC v0 verify.
//
// Drop this verbatim into the FIRST Code node after the Webhook
// trigger in the slack-ingest workflow.
//
// Companion docs:
//   docs/15-slack-edge-adapter-contract.md (the contract)
//   docs/16-slack-n8n-build-runbook.md     (step-by-step n8n setup)
//   scripts/slack_hmac_fixture.py          (Python reference + tests)
//
// Prerequisites:
//   - Webhook node configured with "Raw Body" enabled. The raw bytes
//     must arrive via $binary.data.data (base64); if you parse the
//     body before HMAC, the canonical key ordering shifts and the
//     signature will not match.
//   - n8n credential 'Slack Signing Secret' (Generic Credentials
//     type, single 'value' field). Reference it via
//     $credentials.slackSigningSecret in n8n's credentials helper,
//     OR — if your version doesn't expose it that way — fall back
//     to an n8n environment variable SLACK_SIGNING_SECRET.
//
// Output (single item):
//   { reject: true, reason: '<why>' }              - n8n returns 401
//   { reject: false, eventType: 'url_verification', challenge: '...' } - 200 + challenge
//   { reject: false, eventType: 'event_callback', body: {...} } - continue downstream
//
// The output schema is the contract for the next node (the IF /
// router). Keep the field names stable.

const crypto = require('crypto');

// ---- Get signing secret from credential or env --------------------
let signingSecret = null;
try {
  // Preferred: a Generic Credentials credential in n8n.
  signingSecret = $credentials?.slackSigningSecret?.value ?? null;
} catch (e) { /* credential not bound; fall through */ }
if (!signingSecret) {
  signingSecret = $env?.SLACK_SIGNING_SECRET ?? null;
}
if (!signingSecret) {
  throw new Error(
    'Slack signing secret not found. Bind the "Slack Signing Secret" ' +
    'credential to this Code node OR set SLACK_SIGNING_SECRET in n8n env.'
  );
}

// ---- Pull headers (case-insensitive) -----------------------------
const item = $input.first();
const headers = item.json?.headers ?? {};
const h = {};
for (const k in headers) h[k.toLowerCase()] = headers[k];

const sigHeader = h['x-slack-signature'];
const tsHeader = h['x-slack-request-timestamp'];

if (!sigHeader) {
  return [{ json: { reject: true, reason: 'missing_signature_header' } }];
}
if (!tsHeader) {
  return [{ json: { reject: true, reason: 'missing_timestamp_header' } }];
}

// ---- Replay protection: 5-min skew (Slack-recommended) -----------
const now = Math.floor(Date.now() / 1000);
const ts = parseInt(tsHeader, 10);
if (Number.isNaN(ts) || Math.abs(now - ts) > 300) {
  return [{ json: { reject: true, reason: 'timestamp_skew_exceeded' } }];
}

// ---- Raw body -----------------------------------------------------
// Webhook node with "Raw Body" puts bytes here. Some n8n versions
// route them slightly differently — try the documented path first
// then fall back to alternatives we've seen in 2.x deployments.
let rawBody = null;
try {
  const b64 = item.binary?.data?.data;  // n8n 2.x default for Raw Body
  if (b64) rawBody = Buffer.from(b64, 'base64');
} catch (_e) { /* fall through */ }
if (!rawBody) {
  // Fallback: some webhook configs leave the raw string at item.json.body
  // when the request had Content-Type application/json. NOT
  // canonical — only safe if no JSON re-serialization happened
  // upstream. Use only if Raw Body binary path is unavailable.
  const bodyStr = typeof item.json?.body === 'string'
    ? item.json.body : null;
  if (bodyStr) rawBody = Buffer.from(bodyStr, 'utf8');
}
if (!rawBody) {
  return [{ json: { reject: true, reason: 'raw_body_unavailable' } }];
}

// ---- Compute expected signature ---------------------------------
const base = Buffer.concat([Buffer.from(`v0:${tsHeader}:`), rawBody]);
const expected =
  'v0=' + crypto.createHmac('sha256', signingSecret).update(base).digest('hex');

// ---- Constant-time compare (lengths must match) -----------------
if (sigHeader.length !== expected.length) {
  return [{ json: { reject: true, reason: 'signature_length_mismatch' } }];
}
const a = Buffer.from(sigHeader);
const b = Buffer.from(expected);
if (!crypto.timingSafeEqual(a, b)) {
  return [{ json: { reject: true, reason: 'signature_mismatch' } }];
}

// ---- Verified. Parse body for downstream nodes ------------------
let parsed;
try {
  parsed = JSON.parse(rawBody.toString('utf8'));
} catch (e) {
  return [{ json: { reject: true, reason: 'body_not_json' } }];
}

if (parsed.type === 'url_verification') {
  return [{
    json: {
      reject: false,
      eventType: 'url_verification',
      challenge: parsed.challenge,
    }
  }];
}

return [{
  json: {
    reject: false,
    eventType: parsed.type || 'unknown',
    body: parsed,
  }
}];

// Normalize Slack event — flatten body.event.* into top-level fields
// so downstream IF dispatch nodes can route on $json.slackEventType
// and $json.slackReaction directly. Codex 2026-05-08 review found
// optional-chained expressions in IF nodes were silently routing
// reaction events down the wrong branch. The fix is to do the
// chain-walk once here, in JS, and surface flat fields.

const item = $input.first().json;
const body = item.body || {};
const ev = body.event || {};
const target = ev.item || {};

return [{
  json: {
    // Pass through everything from HMAC Verify so downstream code
    // nodes can still see body.* if they need it.
    ...item,
    // New flat fields the IF dispatch nodes route on:
    slackEventType: ev.type || '',
    slackReaction: ev.reaction || '',
    slackItemType: target.type || '',
    slackItemChannel: target.channel || '',
    slackItemTs: target.ts || '',
  }
}];

// n8n Code node script — build OpsMemory /v1/ingest/slack body.
//
// Drop this verbatim into the Code node AFTER the IF router that
// has separated event_callback events from url_verification.
//
// Input (from HMAC-verify Code node):
//   { reject: false, eventType: 'event_callback', body: {<full slack event>} }
//
// Output (single item, schema below):
//   skip=true      -> downstream IF routes to "Respond 200 silent" (drop)
//   skip=false     -> downstream HTTP Request node POSTs opsMemoryBody
//
// Filtering rules for launch (per Codex Phase C trim):
//   - Only app_mention events go through. Every other subtype
//     (message.channels, message.im, reaction_added, etc.)
//     is dropped silently with skip=true. Reactions are explicitly
//     deferred until threaded-message handling is tested.
//   - Empty messages after stripping the bot mention are dropped.
//   - Bot messages (subtype=bot_message OR ev.bot_id) are dropped
//     to avoid the bot ingesting itself.
//
// Mention stripping:
//   Slack delivers mention text as "<@U01OPSMEM> rest of message".
//   We strip the LEADING bot mention so the LLM extract step doesn't
//   waste tokens on the routing token. Original is preserved in
//   extra.original_text for audit reproduction.

const item = $input.first().json;

// Defensive: if upstream node passed reject:true through somehow,
// drop. (The IF router in front of this node should have handled
// it, but belt-and-braces.)
if (item.reject) {
  return [{ json: { skip: true, reason: 'upstream_reject' } }];
}

const body = item.body;
if (!body) {
  return [{ json: { skip: true, reason: 'no_body' } }];
}

if (body.type !== 'event_callback') {
  return [{ json: { skip: true, reason: 'not_event_callback' } }];
}

const ev = body.event ?? {};
if (ev.type !== 'app_mention') {
  return [{ json: { skip: true, reason: `event_type_${ev.type ?? 'missing'}` } }];
}

// Drop bot messages (bot ingesting itself, or another bot in channel).
if (ev.subtype === 'bot_message' || ev.bot_id) {
  return [{ json: { skip: true, reason: 'bot_message' } }];
}

// Strip leading <@U...> mentions. Slack only routes app_mention to
// us when the bot is mentioned, but the user might have multiple
// mentions in one message ("<@OPSMEMORY> please assign <@JOANNA>...").
// We only strip OUR bot's mention if we know the bot user id; for
// safety strip ALL leading mentions until non-mention content.
const originalText = ev.text ?? '';
const mentionStripped = originalText
  .replace(/^(\s*<@[UW][A-Z0-9]+>\s*)+/, '')
  .trim();

if (mentionStripped.length < 1) {
  return [{ json: { skip: true, reason: 'empty_after_mention_strip' } }];
}

// Build the OpsMemory /v1/ingest/slack body.
// Schema source: api/app/v1_ingest.py SlackIngest pydantic model.
const opsMemoryBody = {
  team_id: body.team_id,
  channel_id: ev.channel,
  ts: ev.ts,
  text: mentionStripped,
  user_id: ev.user ?? null,
  thread_ts: ev.thread_ts ?? null,
  channel_name: null,        // populate via channels:read API if desired
  user_name: null,           // populate via users:read API if desired
  team_domain: null,
  workspace_name: null,
  enterprise_id: body.authorizations?.[0]?.enterprise_id ?? null,
  extra: {
    slack_event_id: body.event_id,
    slack_event_type: 'app_mention',
    original_text: originalText,
    api_app_id: body.api_app_id,
  },
};

return [{
  json: {
    skip: false,
    opsMemoryBody,
    // Convenience fields for n8n IF nodes / logs:
    team_id: body.team_id,
    channel_id: ev.channel,
    ts: ev.ts,
  }
}];

// n8n Code node — prepare a Slack conversations.history call.
//
// Drop this verbatim into the Code node BEFORE the HTTP Request node
// that calls Slack's API on the reaction_added branch. We use a Code
// node here (instead of binding query strings directly on the HTTP
// Request node) because reaction events have several layout variants
// — `item.type='message'` always, but `item.ts` is the canonical
// reacted-to message timestamp regardless of whether the original
// is top-level or threaded.
//
// Companion docs:
//   docs/15-slack-edge-adapter-contract.md (the contract)
//   docs/16-slack-n8n-build-runbook.md     (step-by-step n8n setup)
//
// Input (from the IF "reaction is memo?" upstream):
//   { reject: false, eventType: 'event_callback',
//     body: { event: { type: 'reaction_added', user, reaction,
//                       item: { type, channel, ts }, ... },
//             team_id, event_id, ... } }
//
// Output (single item) — fields the HTTP Request node will reference:
//   slackChannel : the channel id to query
//   slackLatest  : the message ts to look up
//   reaction     : the emoji name (passed through for build-body audit)
//   slackUser    : who reacted (for source_metadata.user_id; the
//                   ingester is the reactor, not the original author —
//                   the original author is recovered from the fetched
//                   message body)
//   teamId       : workspace id
//   eventId      : Slack event_id (idempotency, audit)
//   originalEventBody: the full event payload for downstream build.
//
// We don't strip thread_ts here — the build-body node decides whether
// threaded replies are accepted (they're skipped at launch per Codex
// 2026-05-08 review until cleanly tested).

const item = $input.first().json;
const body = item.body;
if (!body) {
  return [{ json: { skip: true, reason: 'no_body' } }];
}

const ev = body.event;
if (!ev || ev.type !== 'reaction_added') {
  return [{ json: { skip: true, reason: 'not_reaction_added' } }];
}

const target = ev.item;
if (!target || target.type !== 'message') {
  // Reactions can also be on file/file_comment items; we only handle
  // message reactions for the ingest path.
  return [{ json: { skip: true, reason: 'reaction_target_not_message' } }];
}

const channel = target.channel;
const ts = target.ts;
if (!channel || !ts) {
  return [{ json: { skip: true, reason: 'missing_channel_or_ts' } }];
}

return [{
  json: {
    skip: false,
    slackChannel: channel,
    slackLatest: ts,
    reaction: ev.reaction || null,
    slackUser: ev.user || null,
    teamId: body.team_id,
    eventId: body.event_id,
    originalEventBody: body,
  }
}];

// n8n Code node — build OpsMemory /v1/ingest/slack body from a
// reaction_added event whose target message has just been fetched.
//
// Drop this verbatim into the Code node AFTER the HTTP Request node
// that called Slack's conversations.history on the reaction branch.
//
// Input shape (the HTTP Request node forwards both its own response
// AND the prior node's data; in n8n 2.x with default settings the
// previous-node fields ride along on the same item):
//
//   $('Slack: fetch reacted message').first().json   -- conversations.history payload
//   $('Reaction prep').first().json                  -- prepared event metadata
//
// We read both via the `$('<NodeName>')` references rather than
// $input.first() so the input wiring is explicit and stable across
// n8n versions.
//
// Output shape: same as the mention-path Build OpsMemory body:
//   { skip: true, reason: '...' }                              -- drop silently
//   { skip: false, opsMemoryBody: {<SlackIngest body>}, ... }  -- forward to OpsMemory
//
// Filtering rules (top-level messages only at launch, per Codex
// 2026-05-08 review on threaded-reply behavior):
//   - conversations.history must return exactly one message (the one
//     we asked for via inclusive=true&limit=1).
//   - Reject if the message is a reply (thread_ts present and !==
//     the message ts itself).
//   - Reject bot messages and the bot's own messages so the bot
//     can't ingest itself.

const prep = $('Reaction prep').first().json;
const slackResp = $('Slack: fetch reacted message').first().json;

if (prep?.skip) {
  return [{ json: { skip: true, reason: prep.reason || 'upstream_skip' } }];
}

if (!slackResp || slackResp.ok !== true) {
  return [{
    json: {
      skip: true,
      reason: 'slack_history_not_ok',
      slack_error: slackResp?.error || 'unknown',
    }
  }];
}

const messages = Array.isArray(slackResp.messages) ? slackResp.messages : [];
if (messages.length === 0) {
  // The reacted-to message may have been deleted between Slack's
  // event delivery and our fetch. Drop silently — Slack won't retry
  // this delivery once we 200, and there's nothing to ingest.
  return [{ json: { skip: true, reason: 'message_not_found' } }];
}

const msg = messages[0];

// Drop bot messages.
if (msg.subtype === 'bot_message' || msg.bot_id) {
  return [{ json: { skip: true, reason: 'bot_message' } }];
}

// Top-level only at launch.
const isTopLevel = !msg.thread_ts || msg.thread_ts === msg.ts;
if (!isTopLevel) {
  return [{ json: { skip: true, reason: 'threaded_reply_not_supported_yet' } }];
}

const text = (msg.text || '').trim();
if (text.length < 1) {
  return [{ json: { skip: true, reason: 'empty_message_text' } }];
}

const opsMemoryBody = {
  team_id: prep.teamId,
  channel_id: prep.slackChannel,
  ts: msg.ts,                    // canonical event id is the original
                                  // message's ts, NOT the reaction's. Slack
                                  // retries on the SAME reaction event_id
                                  // but our idempotency in OpsMemory keys
                                  // off (team, channel, ts) so multiple
                                  // reactions on the same message dedupe
                                  // to one ingest_event.
  text: text,
  user_id: msg.user || null,      // ORIGINAL author, not the reactor
  thread_ts: msg.thread_ts || null,
  channel_name: null,
  user_name: null,
  team_domain: null,
  workspace_name: null,
  enterprise_id: null,
  extra: {
    slack_event_id: prep.eventId,
    slack_event_type: 'reaction_added',
    reaction: prep.reaction,
    reactor_user_id: prep.slackUser,   // who labeled this as a task
    original_text: msg.text || null,
  },
};

return [{
  json: {
    skip: false,
    opsMemoryBody,
    team_id: prep.teamId,
    channel_id: prep.slackChannel,
    ts: msg.ts,
  }
}];
